        new() { Id = 3, Name = "Dr. Emmy Noether",    Title = "Professor",           Email = "enoether@university.edu",   Bio = "Dr. Noether is a leading researcher in abstract algebra and theoretical physics. She has mentored over 30 doctoral students." },
        new() { Id = 4, Name = "Dr. Richard Feynman", Title = "Professor",           Email = "rfeynman@university.edu",   Bio = "Dr. Feynman is known for his engaging lectures and research in quantum electrodynamics. He has received numerous teaching excellence awards." },
        new() { Id = 5, Name = "Dr. Maya Angelou",    Title = "Professor",           Email = "mangelou@university.edu",   Bio = "Dr. Angelou brings 25 years of literary scholarship and creative writing expertise. She has authored three critically acclaimed novels." },
        new() { Id = 6, Name = "Dr. Howard Zinn",     Title = "Associate Professor", Email = "hzinn@university.edu",      Bio = "Dr. Zinn specializes in social history and civil rights movements. He is the author of several widely adopted history textbooks." },
        new() { Id = 7, Name = "Dr. Rosalind Franklin",Title = "Professor",          Email = "rfranklin@university.edu",  Bio = "Dr. Franklin is an expert in molecular biology and X-ray crystallography. Her lab has made breakthrough discoveries in structural genomics." },
