    ];

    private static List<Instructor> GetInstructors() => InitInstructors();

    private List<Course> InitCourses()
    {
        var instructors = _instructors;
        var departments = _departments;

        Course Make(int id, int deptId, int instrId, string code, string title, string desc,
            int credits, string schedule, string location, int max, int current, bool featured = false)
        {
            var c = new Course
            {
                Id = id, CourseCode = code, Title = title, Description = desc,
                Credits = credits, Schedule = schedule, Location = location,
                MaxEnrollment = max, CurrentEnrollment = current, IsFeatured = featured,
                DepartmentId = deptId, InstructorId = instrId,
                Department = departments.First(d => d.Id == deptId),
                Instructor = instructors.First(i => i.Id == instrId),
            };
            return c;
        }

        return
        [
