            Make( 1, 1, 1, "CS 101", "Introduction to Computer Science",
                "A broad introduction to computer science covering computational thinking, basic programming in Python, and an overview of major sub-fields.",
                3, "Mon/Wed/Fri 9:00–9:50 AM", "Science Hall 101", 120, 98, featured: true),
