            // History
            Make(12, 5, 6, "HIST 101", "World History to 1500",
                "Survey of major civilizations, empires, and cultural developments from prehistory through the late medieval period.",
                3, "Mon/Wed/Fri 2:00–2:50 PM", "Liberal Arts 120", 80, 65),
            Make(13, 5, 6, "HIST 301", "Modern Civil Rights Movements",
                "In-depth study of civil rights movements worldwide from the 20th century to present, with emphasis on primary source analysis.",
