@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@rendermode InteractiveServer
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<div class="row mb-4">
    <div class="col-md-4">
        <label for="search" class="form-label">Search</label>
        <input id="search" type="text" class="form-control" placeholder="Title, code, or instructor…"
               @bind="SearchTerm" @bind:event="oninput" @bind:after="ApplyFilters" />
    </div>
    <div class="col-md-3">
        <label for="dept" class="form-label">Department</label>
        <select id="dept" class="form-select" @bind="SelectedDepartmentId" @bind:after="ApplyFilters">
            <option value="0">All Departments</option>
            @foreach (var dept in Catalog.GetAllDepartments())
            {
                <option value="@dept.Id">@dept.Name (@dept.Code)</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <label for="credits" class="form-label">Credits</label>
        <select id="credits" class="form-select" @bind="SelectedCredits" @bind:after="ApplyFilters">
            <option value="0">Any</option>
            <option value="3">3 Credits</option>
            <option value="4">4 Credits</option>
        </select>
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

<p class="text-muted">Showing @FilteredCourses.Count course(s)</p>

@if (FilteredCourses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Instructor</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th>Availability</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in FilteredCourses)
                {
                    <tr>
                        <td><strong>@course.CourseCode</strong></td>
                        <td>@course.Title</td>
                        <td><span class="badge bg-secondary">@course.Department.Code</span></td>
                        <td>@course.Instructor.Name</td>
                        <td>@course.Credits</td>
                        <td><small>@course.Schedule</small></td>
                        <td>
                            @{
                                var spotsLeft = course.MaxEnrollment - course.CurrentEnrollment;
                                var badgeClass = spotsLeft > 10 ? "bg-success" : spotsLeft > 0 ? "bg-warning text-dark" : "bg-danger";
                            }
                            <span class="badge @badgeClass">@spotsLeft / @course.MaxEnrollment</span>
                        </td>
                        <td>
                            <a href="@($"courses/{course.Id}")" class="btn btn-sm btn-outline-primary">Details</a>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private string SearchTerm { get; set; } = string.Empty;
    private int SelectedDepartmentId { get; set; }
    private int SelectedCredits { get; set; }
    private IReadOnlyList<Course> FilteredCourses { get; set; } = [];

    protected override void OnInitialized()
    {
        if (DepartmentId.HasValue)
            SelectedDepartmentId = DepartmentId.Value;

        ApplyFilters();
    }

    private void ApplyFilters()
    {
        FilteredCourses = Catalog.SearchCourses(SearchTerm, SelectedDepartmentId, SelectedCredits);
    }

    private void ClearFilters()
    {
        SearchTerm = string.Empty;
        SelectedDepartmentId = 0;
        SelectedCredits = 0;
        ApplyFilters();
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>@(Course?.Title ?? "Course Not Found")</PageTitle>

@if (Course is null)
{
    <div class="alert alert-warning">
        <h4>Course Not Found</h4>
        <p>The requested course does not exist. <a href="courses">Browse all courses</a>.</p>
    </div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="">Home</a></li>
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@Course.CourseCode</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1>@Course.CourseCode — @Course.Title</h1>
            <p class="lead">@Course.Description</p>

            <h3 class="mt-4">Course Details</h3>
            <table class="table">
                <tbody>
                    <tr><th style="width:180px">Department</th><td>@Course.Department.Name (@Course.Department.Code)</td></tr>
                    <tr><th>Credits</th><td>@Course.Credits</td></tr>
                    <tr><th>Schedule</th><td>@Course.Schedule</td></tr>
                    <tr><th>Location</th><td>@Course.Location</td></tr>
                    <tr>
                        <th>Availability</th>
                        <td>
                            @{
                                var spotsLeft = Course.MaxEnrollment - Course.CurrentEnrollment;
                            }
                            @Course.CurrentEnrollment / @Course.MaxEnrollment enrolled
                            (@spotsLeft spot@(spotsLeft != 1 ? "s" : "") remaining)
                        </td>
                    </tr>
                </tbody>
            </table>

            <div class="mt-3">
                <a href="@($"enroll?courseId={Course.Id}")" class="btn btn-success">Enroll in This Course</a>
                <a href="courses" class="btn btn-outline-secondary ms-2">← Back to Courses</a>
            </div>
        </div>

        <div class="col-lg-4">
            <div class="card mt-4 mt-lg-0">
                <div class="card-header bg-dark text-white">
                    <h5 class="mb-0">Instructor</h5>
                </div>
                <div class="card-body">
                    <h5>@Course.Instructor.Name</h5>
                    <p class="text-muted mb-1">@Course.Instructor.Title</p>
                    <p class="mb-2">
                        <a href="mailto:@Course.Instructor.Email">@Course.Instructor.Email</a>
                    </p>
                    <hr />
                    <p>@Course.Instructor.Bio</p>
                </div>
            </div>

            @{
                var related = Catalog.GetCoursesByDepartment(Course.DepartmentId)
                    .Where(c => c.Id != Course.Id).ToList();
            }
            @if (related.Count > 0)
            {
                <div class="card mt-3">
                    <div class="card-header">
                        <h5 class="mb-0">Other @Course.Department.Code Courses</h5>
                    </div>
                    <ul class="list-group list-group-flush">
                        @foreach (var c in related)
                        {
                            <li class="list-group-item">
                                <a href="@($"courses/{c.Id}")">@c.CourseCode — @c.Title</a>
                            </li>
                        }
                    </ul>
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    private Course? Course { get; set; }

    protected override void OnInitialized()
    {
        Course = Catalog.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@rendermode InteractiveServer
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Complete the form below to submit an enrollment request. All fields marked with <span class="text-danger">*</span> are required.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>
            Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
            <strong>@SelectedCourseTitle</strong> has been received. You will receive a
            confirmation at <strong>@Model.Email</strong>.
        </p>
        <hr />
        <button class="btn btn-outline-success" @onclick="Reset">Submit Another Request</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="row">
            <div class="col-md-6">
                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name <span class="text-danger">*</span></label>
                    <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
                    <ValidationMessage For="@(() => Model.StudentName)" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                    <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" placeholder="e.g. STU12345" />
                    <ValidationMessage For="@(() => Model.StudentId)" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="email" class="form-label">Email <span class="text-danger">*</span></label>
                    <InputText id="email" class="form-control" @bind-Value="Model.Email" placeholder="student@university.edu" />
                    <ValidationMessage For="@(() => Model.Email)" class="text-danger" />
                </div>
            </div>

            <div class="col-md-6">
                <div class="mb-3">
                    <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in Catalog.GetAllCourses())
                        {
                            var spots = course.MaxEnrollment - course.CurrentEnrollment;
                            <option value="@course.Id" disabled="@(spots <= 0)">
                                @course.CourseCode — @course.Title (@spots spots left)
                            </option>
                        }
                    </InputSelect>
                    <ValidationMessage For="@(() => Model.CourseId)" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="comments" class="form-label">Comments (optional)</label>
                    <InputTextArea id="comments" class="form-control" rows="4" @bind-Value="Model.Comments"
                                   placeholder="Any special requests or notes…" />
                    <ValidationMessage For="@(() => Model.Comments)" class="text-danger" />
                </div>
            </div>
        </div>

        @if (SubmitError)
        {
            <div class="alert alert-danger">
                The selected course is full or could not be found. Please choose another course.
            </div>
        }

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
        <a href="courses" class="btn btn-outline-secondary ms-2">Browse Courses</a>
    </EditForm>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private EnrollmentRequest Model { get; set; } = new();
    private bool Submitted { get; set; }
    private bool SubmitError { get; set; }
    private string SelectedCourseTitle { get; set; } = string.Empty;

    protected override void OnInitialized()
    {
        if (CourseId.HasValue)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        SubmitError = false;

        var success = Catalog.SubmitEnrollmentRequest(Model);
        if (!success)
        {
            SubmitError = true;
            return;
        }

        var course = Catalog.GetCourse(Model.CourseId);
        SelectedCourseTitle = course is not null ? $"{course.CourseCode} — {course.Title}" : "Unknown";
        Submitted = true;
    }

    private void Reset()
    {
        Model = new EnrollmentRequest();
        Submitted = false;
        SubmitError = false;
        SelectedCourseTitle = string.Empty;
    }
}

